    private function maneuverForInstruction(string $instruction): string
    {
        if (str_starts_with($instruction, 'Turn left')) {
            return 'turn_left';
        }

        if (str_starts_with($instruction, 'Turn right') || str_starts_with($instruction, 'Bear right')) {
            return 'turn_right';
        }

        return 'continue';
    }
